      message: "Unsafe SQL operation detected. Only SELECT queries are allowed."
    }
  }
];

const analysis = $input.first().json;

// Get SQL results from Combine Results node
const sqlResults = $('Combine Results').first().json.results;

// Get original user query
const userQuery = $('Webhook').first().json.body.message;

return [
  {
    json: {
      query: userQuery,

      total_results: sqlResults.length,

      results: sqlResults,

      analysis: {
        summary: $input.first().json.output.summary || "", 

        key_insights: $input.first().json.output.key_insights || [],

          business_analysis:   $input.first().json.output.business_analysis || "",

        recommendations: $input.first().json.output.recommendations || [],

        anomalies: $input.first().json.output.anomalies || []
      }
    }
  }
];
